package com.example.demo.controller;
import com.example.demo.dto.CategoryRequest; import com.example.demo.service.SalesService; import org.springframework.http.HttpStatus; import org.springframework.web.bind.annotation.*; import java.util.List;
@RestController @RequestMapping("/api/admin/categories") public class CategoryController {private final SalesService service;public CategoryController(SalesService service){this.service=service;}@GetMapping public List<String> list(@RequestHeader("Authorization")String auth){return service.adminCategories(auth);}@PostMapping public List<String> create(@RequestHeader("Authorization")String auth,@RequestBody CategoryRequest r){return service.createCategory(auth,r);}@PutMapping("/{name}") public List<String> rename(@RequestHeader("Authorization")String auth,@PathVariable String name,@RequestBody CategoryRequest r){return service.renameCategory(auth,name,r);}@DeleteMapping("/{name}") @ResponseStatus(HttpStatus.NO_CONTENT) public void delete(@RequestHeader("Authorization")String auth,@PathVariable String name){service.deleteCategory(auth,name);}}
